  1	import * as React from 'react';
  2	import {
  3	  DR_BLOCK_LISTED_LABELS,
  4	  LABEL,
  5	  LABEL_SPLIT_CHAR,
  6	  LABELS_SPLIT_CHAR,
  7	} from '@odf/mco/constants';
  8	import { useACMSafeFetch } from '@odf/mco/hooks/acm-safe-fetch';
  9	import { SearchResult } from '@odf/mco/types';
 10	import { MultiSelectDropdown } from '@odf/shared/dropdown/multiselectdropdown';
 11	import { SingleSelectDropdown } from '@odf/shared/dropdown/singleselectdropdown';
 12	import { StatusBox } from '@odf/shared/generic/status-box';
 13	import { getName } from '@odf/shared/selectors';
 14	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 15	import { getValidatedProp } from '@odf/shared/utils';
 16	import {
 17	  LazyNameValueEditor,
 18	  NameValueEditorPair,
 19	  PairElementProps,
 20	} from '@odf/shared/utils/NameValueEditor';
 21	import * as _ from 'lodash-es';
 22	import {
 23	  Button,
 24	  ButtonVariant,
 25	  Form,
 26	  FormGroup,
 27	  Grid,
 28	  GridItem,
 29	  Popover,
 30	  SelectOption,
 31	} from '@patternfly/react-core';
 32	import { MinusCircleIcon } from '@patternfly/react-icons';
 33	import '../../../../style.scss';
 34	import { queryAppWorkloadPVCs } from '../../../../utils/acm-search-queries';
 35	import '../style.scss';
 36	import {
 37	  ManagePolicyStateAction,
 38	  ManagePolicyStateType,
 39	  ModalViewContext,
 40	  PVCSelectorType,
 41	} from '../utils/reducer';
 42	import { PlacementType, PVCQueryFilter } from '../utils/types';
 43	import {
 44	  getLabelValidationMessage,
 45	  isValidLabelInput,
 46	} from './assign-policy-view-footer';
 47	
 48	const getPlacementTags = (pvcSelectors: PVCSelectorType[]): TagsType =>
 49	  !!pvcSelectors.length
 50	    ? pvcSelectors.map((pvcSelector, index) => [
 51	        pvcSelector.placementName,
 52	        pvcSelector.labels,
 53	        index,
 54	      ])
 55	    : [['', [], 0]];
 56	
 57	const getLabelsFromSearchResult = (searchResult: SearchResult): string[] => {
 58	  const pvcLabels =
 59	    searchResult?.data.searchResult?.[0]?.related?.[0]?.items?.reduce(
 60	      (acc, item) => {
 61	        const labels: string[] = item[LABEL]?.split(LABELS_SPLIT_CHAR) || [];
 62	        const filteredLabels = labels?.filter((label) => {
 63	          const [key] = label.split(LABEL_SPLIT_CHAR);
 64	          return !DR_BLOCK_LISTED_LABELS.includes(key);
 65	        });
 66	        return [...acc, ...filteredLabels];
 67	      },
 68	      []
 69	    ) || [];
 70	  return Array.from(new Set(pvcLabels));
 71	};
 72	
 73	const getLabelsFromTags = (tags: TagsType, currIndex: number): string[] =>
 74	  tags.reduce((acc, tag, index) => {
 75	    const labels: string[] =
 76	      (tag?.[NameValueEditorPair.Value] as string[]) || [];
 77	    return currIndex !== index ? [...acc, ...labels] : acc;
 78	  }, []) as string[];
 79	
 80	const getPlacementsFromTags = (tags: TagsType, currIndex: number): string[] =>
 81	  tags.reduce((acc, tag, index) => {
 82	    const placement: string = tag?.[NameValueEditorPair.Name] as string;
 83	    return currIndex !== index ? [...acc, placement] : acc;
 84	  }, []) as string[];
 85	
 86	const getPlacementDropdownOptions = (
 87	  placementNames: string[],
 88	  tags: TagsType,
 89	  currIndex: number
 90	) => {
 91	  // Display placement names except selected from other indexes
 92	  const selectedNames = getPlacementsFromTags(tags, currIndex);
 93	  const shortListedNames = placementNames.filter(
 94	    (name) => !selectedNames.includes(name)
 95	  );
 96	  return shortListedNames.map((name) => (
 97	    <SelectOption key={name} value={name}>
 98	      {name}
 99	    </SelectOption>
100	  ));
101	};
102	
103	const getLabelsDropdownOptions = (
104	  labels: string[],
105	  selectedLabels: string[]
106	): JSX.Element[] => {
107	  // Display labels names except selected from other indexes
108	  return labels.reduce(
109	    (acc, name) =>
110	      !selectedLabels.includes(name)
111	        ? [
112	            ...acc,
113	            <SelectOption key={name} value={name}>
114	              {name}
115	            </SelectOption>,
116	          ]
117	        : acc,
118	    []
119	  );
120	};
121	
122	const getPVCSelectors = (
123	  nameValuePairs: TagsType,
124	  protectedPlacementNames: string[]
125	): PVCSelectorType[] =>
126	  nameValuePairs.reduce((acc, pair) => {
127	    const pvcSelector = {
128	      placementName: pair[NameValueEditorPair.Name] as string,
129	      labels: pair[NameValueEditorPair.Value] as string[],
130	    };
131	    return protectedPlacementNames.includes(pvcSelector.placementName)
132	      ? acc
133	      : [...acc, pvcSelector];
134	  }, [] as PVCSelectorType[]);
135	
136	const PairElement: React.FC<PairElementProps> = ({
137	  index,
138	  onRemove: onRemoveProp,
139	  onChange,
140	  isEmpty,
141	  alwaysAllowRemove,
142	  pair,
143	  extraProps,
144	}) => {
145	  const { t } = useCustomTranslation();
146	  const {
147	    unProtectedPlacementNames,
148	    labels,
149	    tags,
150	    isValidationEnabled,
151	    protectedPlacementNames,
152	  }: ExtraProps = extraProps;
153	  const selectedPlacement = pair[NameValueEditorPair.Name];
154	  const selectedLabels = pair[NameValueEditorPair.Value];
155	  // Disable already protected placements for edit mode
156	  const isDisabled = protectedPlacementNames.includes(selectedPlacement);
157	  const deleteIcon = (
158	    <>
159	      <MinusCircleIcon className="pairs-list__side-btn pairs-list__delete-icon" />
160	      <span className="sr-only">{t('Delete')}</span>
161	    </>
162	  );
163	
164	  const onChangePlacement = React.useCallback(
165	    (placement: string) => {
166	      onChange(
167	        { target: { value: placement } },
168	        index,
169	        NameValueEditorPair.Name
170	      );
171	    },
172	    [index, onChange]
173	  );
174	
175	  const onChangeValue = React.useCallback(
176	    (values: string[]) => {
177	      onChange({ target: { value: values } }, index, NameValueEditorPair.Value);
178	    },
179	    [index, onChange]
180	  );
181	
182	  const onRemove = React.useCallback(() => {
183	    onRemoveProp(index);
184	  }, [index, onRemoveProp]);
185	
186	  return (
187	    <Grid hasGutter>
188	      <GridItem lg={5} sm={5}>
189	        <FormGroup hasNoPaddingTop isRequired>
190	          <SingleSelectDropdown
191	            id="placement-selection-dropdown"
192	            selectedKey={selectedPlacement}
193	            selectOptions={getPlacementDropdownOptions(
194	              unProtectedPlacementNames,
195	              tags,
196	              index
197	            )}
198	            placeholderText={t('Select a placement')}
199	            onChange={onChangePlacement}
200	            required
201	            validated={getValidatedProp(
202	              isValidationEnabled && !selectedPlacement
203	            )}
204	            isDisabled={isDisabled}
205	          />
206	        </FormGroup>
207	      </GridItem>
208	
209	      <GridItem lg={5} sm={5}>
210	        <FormGroup hasNoPaddingTop isRequired>
211	          <MultiSelectDropdown
212	            id="labels-selection-dropdown"
213	            selections={selectedLabels}
214	            onChange={onChangeValue}
215	            selectOptions={getLabelsDropdownOptions(
216	              labels,
217	              getLabelsFromTags(tags, index)
218	            )}
219	            placeholderText={
220	              !!selectedLabels?.length
221	                ? t('{{count}} selected', { count: selectedLabels?.length })
222	                : t('Select labels')
223	            }
224	            variant={'checkbox'}
225	            validated={getValidatedProp(
226	              isValidationEnabled && !isValidLabelInput(selectedLabels)
227	            )}
228	            isDisabled={isDisabled}
229	            popperProps={{
230	              position: 'right',
231	            }}
232	            isCreatable={true}
233	            hasInlineFilter={true}
234	          />
235	        </FormGroup>
236	      </GridItem>
237	      <GridItem lg={2} sm={2}>
238	        <FormGroup hasNoPaddingTop>
239	          <Button
240	            type="button"
241	            data-test="delete-button"
242	            onClick={onRemove}
243	            isDisabled={(isEmpty && !alwaysAllowRemove) || isDisabled}
244	            variant="plain"
245	          >
246	            {deleteIcon}
247	          </Button>
248	        </FormGroup>
249	      </GridItem>
250	    </Grid>
251	  );
252	};
253	
254	export const PVCDetailsWizardContent: React.FC<
255	  PVCDetailsWizardContentProps
256	> = ({
257	  pvcSelectors,
258	  unProtectedPlacements,
259	  isValidationEnabled,
260	  protectedPVCSelectors,
261	  dispatch,
262	  pvcQueryFilter,
263	}) => {
264	  const { t } = useCustomTranslation();
265	
266	  // To update placement and label info
267	  const selectedPVCSelectors = React.useMemo(
268	    () => _.cloneDeep(pvcSelectors) || [],
269	    [pvcSelectors]
270	  );
271	
272	  // Selected placement and labels
273	  const [tags, setTags] = React.useState<TagsType>(
274	    getPlacementTags([...protectedPVCSelectors, ...selectedPVCSelectors])
275	  );
276	
277	  // ACM search proxy api call
278	  const searchQuery = React.useMemo(
279	    () => queryAppWorkloadPVCs(pvcQueryFilter),
280	    [pvcQueryFilter]
281	  );
282	  const [searchResult, error, loaded] = useACMSafeFetch(searchQuery);
283	
284	  // All labels
285	  const labels: string[] = React.useMemo(
286	    () => getLabelsFromSearchResult(searchResult),
287	    [searchResult]
288	  );
289	
290	  // All unprotected placements
291	  const unProtectedPlacementNames: string[] =
292	    unProtectedPlacements.map(getName);
293	
294	  // All protected placements
295	  const protectedPlacementNames: string[] = protectedPVCSelectors.map(
296	    (pvcSelector) => pvcSelector.placementName
297	  );
298	
299	  return (
300	    <Form>
301	      <FormGroup>
302	        <span>
303	          {t(
304	            'Use PVC label selectors to effortlessly specify the application resources that need protection. You can also create a custom PVC label selector if one doesn’t exists. For more information, '
305	          )}
306	        </span>
307	        <Popover
308	          aria-label={t('Help')}
309	          bodyContent={getLabelValidationMessage(t)}
310	        >
311	          <Button aria-label={t('Help')} variant={ButtonVariant.link} isInline>
312	            {t('see PVC label selector requirements.')}
313	          </Button>
314	        </Popover>
315	      </FormGroup>
316	      {loaded && !error ? (
317	        <LazyNameValueEditor
318	          nameValuePairs={tags}
319	          updateParentData={({ nameValuePairs }) => {
320	            setTags(nameValuePairs);
321	            dispatch({
322	              type: ManagePolicyStateType.SET_PVC_SELECTORS,
323	              context: ModalViewContext.ASSIGN_POLICY_VIEW,
324	              payload: getPVCSelectors(nameValuePairs, protectedPlacementNames),
325	            });
326	          }}
327	          PairElementComponent={PairElement}
328	          nameString={t('Application resource')}
329	          valueString={t('PVC label selector')}
330	          addString={t('Add application resource')}
331	          extraProps={{
332	            unProtectedPlacementNames,
333	            labels,
334	            tags,
335	            isValidationEnabled,
336	            protectedPlacementNames,
337	          }}
338	          className="co-required mco-manage-policies__nameValue--weight"
339	        />
340	      ) : (
341	        <StatusBox loaded={loaded} loadError={error} />
342	      )}
343	    </Form>
344	  );
345	};
346	
347	type TagsType = (string | string[] | number)[][];
348	
349	type ExtraProps = {
350	  unProtectedPlacementNames: string[];
351	  labels: string[];
352	  tags: TagsType;
353	  isValidationEnabled: boolean;
354	  protectedPlacementNames: string[];
355	};
356	
357	type PVCDetailsWizardContentProps = {
358	  pvcSelectors: PVCSelectorType[];
359	  unProtectedPlacements: PlacementType[];
360	  isValidationEnabled: boolean;
361	  dispatch: React.Dispatch<ManagePolicyStateAction>;
362	  protectedPVCSelectors: PVCSelectorType[];
363	  pvcQueryFilter: PVCQueryFilter;
364	};

