 47	
 48	const getPlacementTags = (pvcSelectors: PVCSelectorType[]): TagsType =>
 49	  !!pvcSelectors.length
 50	    ? pvcSelectors.map((pvcSelector, index) => [
 51	        pvcSelector.placementName,
 52	        pvcSelector.labels,
 53	        index,
 54	      ])
 55	    : [['', [], 0]];
 56	
 57	const getLabelsFromSearchResult = (searchResult: SearchResult): string[] => {
 58	  const pvcLabels =
 59	    searchResult?.data.searchResult?.[0]?.related?.[0]?.items?.reduce(
 60	      (acc, item) => {
 61	        const labels: string[] = item[LABEL]?.split(LABELS_SPLIT_CHAR) || [];
 62	        const filteredLabels = labels?.filter((label) => {
 63	          const [key] = label.split(LABEL_SPLIT_CHAR);
 64	          return !DR_BLOCK_LISTED_LABELS.includes(key);
 65	        });
 66	        return [...acc, ...filteredLabels];
 67	      },
 68	      []
 69	    ) || [];
 70	  return Array.from(new Set(pvcLabels));
 71	};
 72	
 73	const getLabelsFromTags = (tags: TagsType, currIndex: number): string[] =>
 74	  tags.reduce((acc, tag, index) => {
 75	    const labels: string[] =
 76	      (tag?.[NameValueEditorPair.Value] as string[]) || [];
 77	    return currIndex !== index ? [...acc, ...labels] : acc;
 78	  }, []) as string[];
 79	
 80	const getPlacementsFromTags = (tags: TagsType, currIndex: number): string[] =>
 81	  tags.reduce((acc, tag, index) => {
 82	    const placement: string = tag?.[NameValueEditorPair.Name] as string;
 83	    return currIndex !== index ? [...acc, placement] : acc;
 84	  }, []) as string[];
 85	
 86	const getPlacementDropdownOptions = (
 87	  placementNames: string[],
 88	  tags: TagsType,
 89	  currIndex: number
 90	) => {
 91	  // Display placement names except selected from other indexes
 92	  const selectedNames = getPlacementsFromTags(tags, currIndex);
 93	  const shortListedNames = placementNames.filter(
 94	    (name) => !selectedNames.includes(name)
 95	  );
 96	  return shortListedNames.map((name) => (
 97	    <SelectOption key={name} value={name}>
 98	      {name}
 99	    </SelectOption>
100	  ));
101	};
102	
103	const getLabelsDropdownOptions = (
104	  labels: string[],
105	  selectedLabels: string[]
106	): JSX.Element[] => {
107	  // Display labels names except selected from other indexes
108	  return labels.reduce(
109	    (acc, name) =>
110	      !selectedLabels.includes(name)
111	        ? [
112	            ...acc,
113	            <SelectOption key={name} value={name}>
114	              {name}
115	            </SelectOption>,
116	          ]
117	        : acc,
118	    []
119	  );
120	};
